        // Clean up temp file on verification or rename failure
        try { unlinkSync(tmpPath) } catch { /* ignore cleanup errors */ }
        throw verifyErr
      }
    } catch (e) {
      console.error('[SessionStore] Failed to save workspace:', e)
    }
  }
